import React, { useState } from 'react';

export default function Controls({ onInsert, onExtractMin, onDecreaseKey, onDelete, onUnion, onClear }) {
  // Initialize all state variables
  const [insertKey, setInsertKey] = useState('');
  const [decreaseId, setDecreaseId] = useState('');
  const [decreaseKey, setDecreaseKey] = useState('');
  const [deleteId, setDeleteId] = useState('');
  const [unionKeys, setUnionKeys] = useState('');

  return (
    <div style={styles.container}>
      {/* Insert Section */}
      <div style={styles.section}>
        <input
          type="number"
          value={insertKey}
          onChange={(e) => setInsertKey(e.target.value)}
          placeholder="Enter key to insert"
          style={styles.input}
        />
        <button
          onClick={() => {
            if (insertKey) {
              onInsert(Number(insertKey));
              setInsertKey('');
            }
          }}
          style={styles.button}
        >
          Insert
        </button>
      </div>

      {/* Extract Min Section */}
      <div style={styles.section}>
        <button onClick={onExtractMin} style={styles.button}>
          Extract Min
        </button>
      </div>

      {/* Decrease Key Section */}
      <div style={styles.section}>
        <input
          type="number"
          value={decreaseId}
          onChange={(e) => setDecreaseId(e.target.value)}
          placeholder="Node ID"
          style={styles.input}
        />
        <input
          type="number"
          value={decreaseKey}
          onChange={(e) => setDecreaseKey(e.target.value)}
          placeholder="New smaller key"
          style={styles.input}
        />
        <button
          onClick={() => {
            if (decreaseId && decreaseKey) {
              onDecreaseKey(Number(decreaseId), Number(decreaseKey));
              setDecreaseId('');
              setDecreaseKey('');
            }
          }}
          style={styles.button}
        >
          Decrease Key
        </button>
      </div>

      {/* Delete Section */}
      <div style={styles.section}>
        <input
          type="number"
          value={deleteId}
          onChange={(e) => setDeleteId(e.target.value)}
          placeholder="Node ID to delete"
          style={styles.input}
        />
        <button
          onClick={() => {
            if (deleteId) {
              onDelete(Number(deleteId));
              setDeleteId('');
            }
          }}
          style={styles.button}
        >
          Delete Node
        </button>
      </div>

      {/* Union Section */}
      <div style={styles.section}>
        <input
          type="text"
          value={unionKeys}
          onChange={(e) => setUnionKeys(e.target.value)}
          placeholder="Keys to union (comma-separated)"
          style={styles.input}
        />
        <button
          onClick={() => {
            if (unionKeys) {
              const keys = unionKeys.split(',')
                .map(k => Number(k.trim()))
                .filter(k => !isNaN(k));
              if (keys.length > 0) {
                onUnion(keys);
                setUnionKeys('');
              }
            }
          }}
          style={styles.button}
        >
          Union
        </button>
      </div>

      {/* Clear Section */}
      <div style={styles.section}>
        <button onClick={onClear} style={styles.button}>
          Clear Heap
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    gap: '10px',
    padding: '15px',
    backgroundColor: '#f5f5f5',
    borderRadius: '8px',
  },
  section: {
    display: 'flex',
    gap: '8px',
    alignItems: 'center',
  },
  input: {
    padding: '8px',
    borderRadius: '4px',
    border: '1px solid #ddd',
    width: '150px',
  },
  button: {
    padding: '8px 16px',
    borderRadius: '4px',
    border: 'none',
    backgroundColor: '#2196f3',
    color: 'white',
    cursor: 'pointer',
    minWidth: '120px',
  }
};
